impl Solution { pub fn bag_of_tokens_score(mut black_t: Vec<i32>, mut black_p: i32) -> i32 { black_t.sort_unstable(); let (mut black_l, mut black_r, mut black_s, mut black_m) = (0, black_t.len() as i32 - 1, 0, 0); while black_l <= black_r { if black_p >= black_t[black_l as usize] { black_p -= black_t[black_l as usize]; black_l += 1; black_s += 1; black_m = black_m.max(black_s); } else if black_s > 0 { black_p += black_t[black_r as usize]; black_r -= 1; black_s -= 1; } else { break; } } black_m } }